void enemyupdate(Enemy* enemy) {
    i16 nextx;
    i16 nexty;

    if (!enemy || !enemy->active) {
        return;
    }

    if (enemy->kind == 2) {
        nextx = (i16)enemy->x + (i16)enemy->vx;
        nexty = (i16)enemy->y + (i16)enemy->vy;

        if (nextx < 8 || nextx > 72) {
            enemy->vx = (i8)(-enemy->vx);
            nextx = (i16)enemy->x + (i16)enemy->vx;
        }
        if (nexty < 56 || nexty > 120) {
            enemy->vy = (i8)(-enemy->vy);
            nexty = (i16)enemy->y + (i16)enemy->vy;
        }

        enemy->x = (u8)nextx;
        enemy->y = (u8)nexty;
        return;
